VALUES
  ('optometrist-moex-02034', 'optometrist', 'optometrist-moex-108-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關兒童視力發育的敘述，下列何者正確？', '["大部分剛出生的嬰兒為正視眼（emmetropia），只是視覺功能尚未成熟，因此視力不佳", "兒童因未發育完整，調節力（accommodation）比成年人弱", "2歲至6歲間一般為弱視預防治療的黃金時期", "兒童弱視篩檢的標準為裸視小於1.0"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "50ef9609ef1a", "answer_pdf_sha1": "ae87821b37cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02035', 'optometrist', 'optometrist-moex-108-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關兒童低視力檢查辦法，下列敘述何者錯誤？', '["Titmus test（stereo fly test）立體試驗必須要配合偏光眼鏡才能進行", "兒童進行Titmus test（stereo fly test）時，觀察到其受試兒童可以辨識立體蒼蠅圖的蒼蠅但無法對應出其 視力值", "若欲開立亂點圖檢查，而受試兒童本身無法辨認基本圖型，會檢查失敗", "魏氏四點檢查（Worth four-dot test）除了能檢查融合視力之外，也能檢查是否有複視的情形"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "50ef9609ef1a", "answer_pdf_sha1": "ae87821b37cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02036', 'optometrist', 'optometrist-moex-108-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '欲檢查一未滿兩歲嬰兒之視力，下列工具何者不適宜？', '["視覺誘發電位", "優先注視法（preferential looking）", "眼睛固視行為表現（fixation behavior）", "E 視標檢測（E chart）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "50ef9609ef1a", "answer_pdf_sha1": "ae87821b37cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02037', 'optometrist', 'optometrist-moex-108-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '遠視+10.00 D的低視力病患，在不戴眼鏡的情況下，使用開普勒望遠鏡（目鏡+40 D, 物鏡+20 D）時，兩 個光學系統之間的距離（調焦後的鏡筒長度）約為多少？', '["6.8 cm", "7.5 cm", "8.3 cm", "9.0 cm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "50ef9609ef1a", "answer_pdf_sha1": "ae87821b37cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02038', 'optometrist', 'optometrist-moex-108-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '教導近視未矯正的低視力患者使用放大鏡時需要注意的事項，下列敘述何者正確？', '["當眼睛到放大鏡的距離等於放大鏡的焦距時，整體放大倍率會比原放大鏡還要高", "當眼睛到放大鏡的距離大於放大鏡的焦距時，整體放大倍率會比原放大鏡還要高", "當眼睛到放大鏡的距離小於放大鏡的焦距時，整體放大倍率會比原放大鏡還要高", "當眼睛到放大鏡的距離大於放大鏡的焦距時，整體放大倍率等於原放大鏡的倍率"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "50ef9609ef1a", "answer_pdf_sha1": "ae87821b37cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02039', 'optometrist', 'optometrist-moex-108-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '若未合併其他眼睛疾病，下列何者不是視覺皮質損傷患者的特質？', '["眼球震顫", "手眼協調有問題", "複雜背景辨識困難", "視覺延宕"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "50ef9609ef1a", "answer_pdf_sha1": "ae87821b37cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02040', 'optometrist', 'optometrist-moex-108-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '除了生理電位檢查之外，對於無法口語的認知功能缺損病患，對於其量測視力的方法，下列敘述何者正確？', '["可使用非口語視力量測法，量測其視力值，沒有視力值就無法進行光學或非光學輔具的處方，也無從 評估輔具介入的成效", "需訓練其病患指認方向、數字或符號時才能量測", "相關的視覺反應都是無效且沒有科學根據的紀錄", "記錄病患生活的表現與行動即可得知其視力改變的狀況"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "50ef9609ef1a", "answer_pdf_sha1": "ae87821b37cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
